package com.example.cms.data.audit; import org.springframework.jdbc.core.JdbcTemplate;import org.springframework.stereotype.Service;import java.util.*; @Service public class AuditLogQueryService{private final JdbcTemplate jdbc; public AuditLogQueryService(JdbcTemplate jdbc){this.jdbc=jdbc;} public List<Map<String,Object>> list(){return jdbc.queryForList("select * from audit_logs order by created_at desc limit 100");}}
